// 读取当前 Writer 文档的完整文本内容
var doc = Application.ActiveDocument;
var text = '';
if (doc && doc.Sections) {
    for (var i = 0; i < doc.Sections.Count; i++) {
        var section = doc.Sections.Item(i + 1);
        if (section.Paragraphs) {
            for (var j = 1; j <= section.Paragraphs.Count; j++) {
                var para = section.Paragraphs.Item(j);
                if (para.Range && para.Range.Text) {
                    text += para.Range.Text.replace(/\u000c/g, '');
                }
            }
        }
    }
}
return {text: text.substring(0, 20000)};

// 尝试通过 Selection 或 Range 获取文档内容
var doc = Application.ActiveDocument;
var text = '';
if (doc && doc.Content) {
    text = doc.Content.Text.replace(/\u000c/g, '');
}
return {text: text.substring(0, 20000)};
